import { Button, createTheme, Tab, Tabs, TextField, ThemeProvider } from "@material-ui/core";
import { useEffect, useState } from "react";
import SearchIcon from '@material-ui/icons/Search';
import axios from "axios";
import CustomPagination from "../../components/Pagination/CustomPagination";
import SingleContent from "../../components/singleContent/SingleContent";

const Search = () => {

    const [page, setPage] = useState(1);
    const [type, setType] = useState(0);
    const [searchText, setSearchText] = useState("");
    const [content, setContent] = useState();
    const [numOfPage, setNumOfPage] = useState()

    const darkTheme=createTheme({
        palette: {
            type:'dark',
            primary:{
                main:"#fff"
            }
        }
    });

    const fetchSearch = async () => {
        try{
            const { data } = await axios.get(
                `https://api.themoviedb.org/3/search/${type ? "tv" : "movie"}?api_key=${
                  process.env.REACT_APP_API_KEY
                }&language=en-US&query=${searchText}&page=${page}&include_adult=false`
              );
              setContent(data.results);
              setNumOfPage(data.total_pages);
        }
        catch(error){
            console.error(error);
        }
    };

    useEffect(() => {
        window.scroll(0,0);
        fetchSearch();
        // eslint-disable-next-line
    }, [page,type])
    
    return (
        <div>
            <ThemeProvider theme={darkTheme}>
                <div style={{display:"flex", margin:"15px 0"}}>

            <TextField 
                style={{flex:1}}
                className="searchBox"
                label="Search"
                variant="filled"
                onChange={(e)=> setSearchText(e.target.value)}
            />
            <Button variant='contained' style={{marginLeft:10}} onClick={fetchSearch}><SearchIcon/></Button>
            </div>
            <Tabs value={type} indicatorColor="primary" textColor="primary" onChange={(event,newValue)=>{
                setType(newValue);
                setPage(1);
            }} style={{paddingBottom:5}}>
                <Tab style={{width:"50%"}} label="Search Movies" />
                <Tab style={{width:"50%"}} label="Search TV Series" />
            </Tabs>
            </ThemeProvider>
            <div className="trending">
                
        {content &&
          content.map((c) => (
            <SingleContent
              key={c.id}
              id={c.id}
              poster={c.poster_path}
              title={c.title || c.name}
              date={c.first_air_date || c.release_date}
              media_type={type ? "tv" : "movie"}
              vote_average={c.vote_average}
            />
          ))}
        
         { content && content.length === 0 ? <h2>Not Found</h2> : ""}
                
            
      </div>
      {numOfPage > 1 && (
        <CustomPagination setPage={setPage} numOfPage={numOfPage} />
      )}
    </div>
    )
}

export default Search